#include <iostream>

class Clamp {
    int m_lo{};
    int m_hi{};
public:
    Clamp(int lo, int hi) : m_lo{ lo }, m_hi{ hi } {}

    int operator()(int x) const {
        if (x < m_lo) return m_lo;
        if (x > m_hi) return m_hi;
        return x;
    }
};

int main() {
    int lo{}, hi{};
    std::cin >> lo >> hi;
    Clamp clamp{ lo, hi };
    int n{};
    std::cin >> n;
    for (int i = 0; i < n; ++i) {
        int v{};
        std::cin >> v;
        std::cout << clamp(v) << '\n';
    }
    return 0;
}

