solution_code:
#include <iostream>

class RunningAverage {
    int m_sum{ 0 };
    int m_count{ 0 };
public:
    double operator()(int x) {
        m_sum += x;
        ++m_count;
        return m_sum / (double)m_count;
    }
};

int main() {
    int n{};
    std::cin >> n;
    RunningAverage avg;
    std::cout << std::fixed;
    std::cout.precision(2);
    for (int i = 0; i < n; ++i) {
        int v{};
        std::cin >> v;
        std::cout << avg(v) << '\n';
    }
    return 0;
}
